-----------------
-- 组态表结构
-- 注意：不管主系统是哪个版本，以下表结构一定要整合到主系统sql文件里，或者单独在数据库执行
-----------------
CREATE TABLE `scada` (
                         `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id唯一标识',
                         `guid` varchar(128) DEFAULT NULL COMMENT '组态id',
                         `scada_data` longtext COMMENT '组态信息',
                         `serial_numbers` varchar(50) DEFAULT NULL COMMENT '设备编号',
                         `device_name` varchar(128) DEFAULT NULL COMMENT '设备名称',
                         `is_main_page` int(1) DEFAULT NULL COMMENT '是否主界面',
                         `page_name` varchar(20) DEFAULT NULL COMMENT '页面名称',
                         `page_resolution` varchar(20) DEFAULT NULL COMMENT '页面大小',
                         `is_share` int(1) DEFAULT NULL COMMENT '是否分享',
                         `share_url` longtext COMMENT '分享链接',
                         `share_pass` varchar(50) DEFAULT NULL COMMENT '分享密码',
                         `page_image` varchar(2000) DEFAULT NULL COMMENT '页面图片',
                         `tenant_id` bigint(20) DEFAULT NULL COMMENT '租户id',
                         `tenant_name` varchar(30) DEFAULT NULL COMMENT '租户名称',
                         `create_by` varchar(50) DEFAULT NULL COMMENT '创建人',
                         `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                         `update_by` varchar(50) DEFAULT NULL COMMENT '更新人',
                         `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                         `del_flag` tinyint(2) NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
                         `remark` varchar(800) CHARACTER SET utf8mb4 DEFAULT NULL COMMENT '备注',
                         PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='组态页面';



CREATE TABLE `scada_component` (
                                   `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键id',
                                   `component_name` varchar(20) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT '组件名称',
                                   `component_template` longtext COLLATE utf8_unicode_ci COMMENT '组件模版',
                                   `component_style` longtext COLLATE utf8_unicode_ci COMMENT '组件风格',
                                   `component_script` longtext COLLATE utf8_unicode_ci COMMENT '组件脚本',
                                   `component_image` varchar(100) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT '组件缩略图',
                                   `tenant_id` bigint(20) DEFAULT NULL COMMENT '租户id',
                                   `tenant_name` varchar(30) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT '租户名称',
                                   `create_by` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT '创建人',
                                   `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                   `update_by` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL COMMENT '更新人',
                                   `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                   `del_flag` tinyint(2) NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
                                   `is_share` int(1) DEFAULT '1' COMMENT '分享类型（0-私有；1-公有）',
                                   `user_id` bigint(20) DEFAULT NULL COMMENT '用户id',
                                   PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci COMMENT='组态组件表';



CREATE TABLE `scada_device_bind` (
                                     `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id唯一标识',
                                     `serial_number` varchar(20) DEFAULT NULL COMMENT '设备编号',
                                     `scada_guid` varchar(128) DEFAULT NULL COMMENT '组态guid',
                                     PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=56 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='组态设备关联表';



CREATE TABLE `scada_echart` (
                                `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id',
                                `guid` varchar(128) CHARACTER SET utf8 DEFAULT NULL,
                                `echart_name` varchar(20) DEFAULT NULL COMMENT '图表名称',
                                `echart_type` varchar(10) DEFAULT NULL COMMENT '图表类别',
                                `echart_data` longtext COMMENT '图表内容',
                                `echart_imgae` varchar(255) DEFAULT NULL COMMENT '图表图片',
                                `tenant_id` bigint(20) DEFAULT NULL COMMENT '租户id',
                                `tenant_name` varchar(30) DEFAULT NULL COMMENT '租户名称',
                                `create_by` varchar(50) CHARACTER SET utf8 DEFAULT NULL COMMENT '创建人',
                                `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                `update_by` varchar(50) CHARACTER SET utf8 DEFAULT NULL COMMENT '更新人',
                                `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                `del_flag` tinyint(2) NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
                                PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='图表管理';

CREATE TABLE `scada_gallery` (
                                 `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'id唯一标识',
                                 `file_name` varchar(255) DEFAULT NULL COMMENT '文件名称',
                                 `category_name` varchar(255) DEFAULT NULL COMMENT '分类名称',
                                 `resource_url` varchar(512) DEFAULT NULL COMMENT '资源请求路径',
                                 `tenant_id` bigint(20) DEFAULT NULL COMMENT '租户id',
                                 `tenant_name` varchar(30) DEFAULT NULL COMMENT '租户名称',
                                 `create_by` varchar(50) DEFAULT NULL COMMENT '创建人',
                                 `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                                 `update_by` varchar(50) DEFAULT NULL COMMENT '更新人',
                                 `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                                 `del_flag` tinyint(2) DEFAULT '0' COMMENT '逻辑删除标识',
                                 PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='组态图库表';

CREATE TABLE `scada_model` (
                               `id` bigint(20) NOT NULL AUTO_INCREMENT,
                               `model_name` varchar(50) DEFAULT NULL COMMENT '模型名称',
                               `model_url` varchar(512) DEFAULT NULL COMMENT '模型地址',
                               `status` int(1) DEFAULT NULL COMMENT '是否弃用',
                               `image_url` varchar(512) DEFAULT NULL COMMENT '缩略图url',
                               `tenant_id` bigint(20) DEFAULT NULL COMMENT '租户id',
                               `tenant_name` varchar(30) DEFAULT NULL COMMENT '租户名称',
                               `create_by` varchar(50) DEFAULT NULL COMMENT '创建人',
                               `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
                               `update_by` varchar(50) DEFAULT NULL COMMENT '更新人',
                               `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
                               `del_flag` tinyint(2) NOT NULL DEFAULT '0' COMMENT '逻辑删除标识',
                               PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='三维配置表';



